AS $function$
DECLARE
  v_action text;
  v_new jsonb := to_jsonb(NEW);
  v_old jsonb := to_jsonb(OLD);
BEGIN
  IF TG_OP = 'INSERT' THEN v_action := 'insert';
  ELSIF TG_OP = 'UPDATE' THEN v_action := 'update';
